import React, { useEffect } from "react";
import { MapContainer, TileLayer, useMap } from "react-leaflet";
import IssMarker from "./IssMarker";

function TrackIssView({ position }) {
  const map = useMap();

  useEffect(() => {
    if (!position) {
      return;
    }

    map.flyTo([position.latitude, position.longitude], map.getZoom(), {
      animate: true,
      duration: 1.5,
    });
  }, [map, position]);

  return null;
}

export default function MapView({ position }) {
  const initialCenter = position
    ? [position.latitude, position.longitude]
    : [0, 0];

  return (
    <div
      style={{
        border: "1px solid #dbe2ea",
        borderRadius: "12px",
        overflow: "hidden",
      }}
    >
      <MapContainer
        center={initialCenter}
        zoom={3}
        minZoom={2}
        style={{ height: "480px", width: "100%" }}
        worldCopyJump
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />
        <IssMarker position={position} />
        <TrackIssView position={position} />
      </MapContainer>
    </div>
  );
}
